using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with the default reflection-based resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable, so this succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not found");

// Now use a source-gen-only context that knows about Person but NOT about Order.
var sgOptions = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

if (sgOptions.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("TryGetTypeInfo<Person> on source-gen → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on source-gen → not found");

if (sgOptions.TryGetTypeInfo<Order>(out _))
    Console.WriteLine("TryGetTypeInfo<Order>  on source-gen → found");
else
    Console.WriteLine("TryGetTypeInfo<Order>  on source-gen → not found  (expected)");

// --- Types ---
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only includes Person
[JsonSerializable(typeof(Person))]
public partial class MyContext : JsonSerializerContext;

